import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class ChatDateSeparator extends StatelessWidget { final DateTime date; const ChatDateSeparator({super.key, required this.date}); @override Widget build(BuildContext context) { final now = DateTime.now(); final label = date.year == now.year && date.month == now.month && date.day == now.day ? 'Today' : date.year == now.year && date.month == now.month && date.day == now.day - 1 ? 'Yesterday' : '${date.day}/${date.month}/${date.year}'; return Padding(padding: const EdgeInsets.symmetric(vertical: 12), child: Row(children: [const Expanded(child: Divider(color: AppTheme.darkBorder)), Padding(padding: const EdgeInsets.symmetric(horizontal: 12), child: Text(label, style: const TextStyle(color: AppTheme.darkSubtext, fontSize: 11))), const Expanded(child: Divider(color: AppTheme.darkBorder))])); } }